```javascript
// Obtener acceso a la cámara
navigator.mediaDevices.getUserMedia({ video: true })
 .then((stream) => {
    // Crear un objeto de video para mostrar la cámara
    const video = document.createElement('video');
    video.srcObject = stream;
    document.body.appendChild(video);

    // Agregar un botón para tomar la foto
    const botonTomarFoto = document.createElement('button');
    botonTomarFoto.textContent = 'Tomar foto';
    document.body.appendChild(botonTomarFoto);

    // Agregar un evento de click al botón
    botonTomarFoto.addEventListener('click', () => {
      // Crear un objeto de canvas para dibujar la imagen
      const canvas = document.createElement('canvas');
      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;
      const ctx = canvas.getContext('2d');
      ctx.drawImage(video, 0, 0, canvas.width, canvas.height);

      // Obtener la imagen del canvas
      const imagen = canvas.toDataURL('image/jpeg');

      // Crear un objeto de blob con la imagen
      const blob = new Blob([imagen], { type: 'image/jpeg' });

      // Crear un enlace para descargar la imagen
      const enlace = document.createElement('a');
      enlace.href = URL.createObjectURL(blob);
      enlace.download = 'foto.jpg';
      enlace.click();

      // Eliminar el canvas y el video
      canvas.remove();
      video.remove();
      botonTomarFoto.remove();
    });
  })
 .catch((error) => {
    console.error('Error al obtener acceso a la cámara:', error);
  });
```

